// Parse struktur pesan dari Meta WhatsApp Business API
// Handle dua format: langsung dari Meta atau wrapped dari Hoppscotch/test
const raw = $input.first().json;
const body = raw.body ? raw.body : raw;

// Handle Meta webhook verification (GET request)
if (body['hub.mode']) {
  return [{ json: { isVerification: true, challenge: body['hub.challenge'] } }];
}

// Extract pesan
const entry = body && body.entry && body.entry[0];
const change = entry && entry.changes && entry.changes[0];
const value = change && change.value;
const message = value && value.messages && value.messages[0];

if (!message) {
  return [{ json: { skip: true, reason: 'No message found' } }];
}

// Skip jika bukan text message
if (message.type !== 'text') {
  return [{ json: { skip: true, reason: 'Non-text message: ' + message.type } }];
}

const contact = value.contacts && value.contacts[0];

return [{
  json: {
    skip: false,
    messageId: message.id,
    from: message.from,
    clientName: contact && contact.profile ? contact.profile.name : 'Pelanggan',
    text: message.text.body,
    timestamp: message.timestamp,
    phoneNumberId: value.metadata.phone_number_id || '1052743247932102',
    waBusinessId: value.metadata.display_phone_number
  }
}];

